 1	import React, { Dispatch, FC, SetStateAction, useState } from 'react';
 2	
 3	import { V1CPU } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import VCPUInput from '@kubevirt-utils/components/CPUMemoryModal/components/CPUInput/components/vCPUInput/VCPUInput';
 5	import {
 6	  convertTopologyToVCPUs,
 7	  CPUInputType,
 8	  formatVCPUsAsSockets,
 9	} from '@kubevirt-utils/components/CPUMemoryModal/components/CPUInput/utils/utils';
10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
11	import { Button, ButtonVariant, Popover, Radio, Title, TitleSizes } from '@patternfly/react-core';
12	import { HelpIcon } from '@patternfly/react-icons';
13	
14	import CPUTopologyInput from './components/CPUTopologyInput/CPUTopologyInput';
15	import CPUHelperText from './components/vCPUInput/components/CPUHelperText/CPUHelperText';
16	
17	import './CPUInput.scss';
18	
19	type CPUInputProps = {
20	  currentCPU: V1CPU;
21	  setUserEnteredCPU: Dispatch<SetStateAction<V1CPU>>;
22	  userEnteredCPU: V1CPU;
23	};
24	
25	const CPUInput: FC<CPUInputProps> = ({ currentCPU, setUserEnteredCPU, userEnteredCPU }) => {
26	  const { t } = useKubevirtTranslation();
27	  const [selectedRadioOption, setSelectedRadioOption] = useState<CPUInputType>(
28	    CPUInputType.editVCPU,
29	  );
30	
31	  const radioInputName = 'cpu-input-type';
32	
33	  return (
34	    <div className="cpu-input">
35	      <Title className="cpu-input__title" headingLevel="h6" size={TitleSizes.md}>
36	        {t('CPU')}
37	        <Popover
38	          bodyContent={t(
39	            'As a default, the VirtualMachine CPU uses sockets to enable hotplug. You can also define the topology manually',
40	          )}
41	        >
42	          <Button
43	            aria-label="Action"
44	            className="cpu-input__title--help-text-button"
45	            variant={ButtonVariant.plain}
46	          >
47	            <HelpIcon />
48	          </Button>
49	        </Popover>
50	      </Title>
51	      <Radio
52	        body={
53	          <VCPUInput
54	            cpu={formatVCPUsAsSockets(userEnteredCPU)}
55	            isDisabled={selectedRadioOption !== CPUInputType.editVCPU}
56	            setCPU={setUserEnteredCPU}
57	          />
58	        }
59	        onClick={() => {
60	          setSelectedRadioOption(CPUInputType.editVCPU);
61	        }}
62	        id={CPUInputType.editVCPU}
63	        isChecked={selectedRadioOption === CPUInputType.editVCPU}
64	        isLabelWrapped
65	        name={radioInputName}
66	      />
67	      <CPUHelperText
68	        cpu={userEnteredCPU}
69	        hide={userEnteredCPU?.sockets === convertTopologyToVCPUs(currentCPU)}
70	      />
71	      <Radio
72	        body={
73	          <CPUTopologyInput
74	            cpu={userEnteredCPU}
75	            hide={selectedRadioOption !== CPUInputType.editTopologyManually}
76	            isDisabled={selectedRadioOption !== CPUInputType.editTopologyManually}
77	            setCPU={setUserEnteredCPU}
78	          />
79	        }
80	        onClick={() => {
81	          setSelectedRadioOption(CPUInputType.editTopologyManually);
82	        }}
83	        className="cpu-input__edit-topology-manually"
84	        id={CPUInputType.editTopologyManually}
85	        isChecked={selectedRadioOption === CPUInputType.editTopologyManually}
86	        label={<>{t('Set CPU topology manually')}</>}
87	        name={radioInputName}
88	      />
89	    </div>
90	  );
91	};
92	
93	export default CPUInput;

